#include <iostream>
#include <fstream>
#include <string>

int main() {
    std::ifstream file("input.txt");
    if (!file.is_open()) {
        std::cerr << "Error opening file." << std::endl;
        return 1;
    }

    std::string word;
    int count = 0;

    while (file >> word) {
        count += (word == "hello")? 1 : 0;
    }

    std::cout << "Word \"" << word << "\" occurs " << count << " time(s)." << std::endl;

    file.close();

    return 0;
}
